### Conditional Redirect with NextResponse.redirect in Next.js Proxy

Source: https://github.com/vercel/next.js/blob/canary/docs/01-app/02-guides/redirecting.mdx

Redirects unauthenticated users to a login page using `NextResponse.redirect` within a Next.js Proxy function. The `config` object defines the matcher for the proxy to apply this logic.

```ts
import { NextResponse, NextRequest } from 'next/server'
import { authenticate } from 'auth-provider'

export function proxy(request: NextRequest) {
  const isAuthenticated = authenticate(request)

  // If the user is authenticated, continue as normal
  if (isAuthenticated) {
    return NextResponse.next()
  }

  // Redirect to login page if not authenticated
  return NextResponse.redirect(new URL('/login', request.url))
}

export const config = {
  matcher: '/dashboard/:path*',
}
```

